<template>
	<view>
		<!-- #ifdef H5 -->
		<view v-if="!$util.browserType('weixin')">
			<view class="text-section">
				<view>{{ content }}</view>
			</view>

		</view>
		<!-- #endif -->
		<view v-if="$util.browserType('weixin') && !ordersn">
			<view class="text-section" v-if="ordersn">
				<view>点击复制网址去浏览器中打开</view>
				<!-- <view class="link">{{ link }}</view> -->
			</view>
			<view class="button-section">
				<!-- #ifdef H5 -->
				<button class="button copy" @click="copyLink">点击复制</button>
				<!-- #endif -->
				<!-- #ifdef MP -->
				<button class="button copy" @click="copyLink">点击复制</button>
				<!-- #endif -->
				<button class="button off" @click="goDetail">完成支付</button>
			</view>

		</view>

		<view v-if="$util.browserType('weixin') && ordersn">
			<view class="text-section" v-if="ordersn">
				<view>支付进行中</view>
				<!-- <view class="link">{{ link }}</view> -->
			</view>
			<view class="button-section">
				<!-- #ifdef H5 -->
				<button class="button copy" @click="$util.back()">未完成支付</button>
				<!-- #endif -->
				<!-- #ifdef MP -->
				<button class="button copy" @click="$util.back()">未完成支付</button>
				<!-- #endif -->
				<button class="button off" @click="goDetail">完成支付</button>
			</view>
		</view>

		<!-- #ifdef H5   -->
		<!-- <view v-show="hintShow && !ordersn" class="hint" @click="hintShow = false">
			<view>点击右上角<text class="iconfont icon-gengduo"></text></view>
			<view>选择 在浏览器 打开，去支付</view>
		</view> -->
		<!-- #endif -->

	</view>
</template>

<script>
	export default {

		data() {
			return {
				// #ifdef H5
				isWeixin: this.$util.browserType('weixin'),
				hintShow: true,
				// #endif
				order_id: '',
				ordersn: '',
				defaultpay: '',
				redirect_url: '', //分站地址
				redirect: '', //主站地址
				link: '',
				pay_id:'',
				pay_key: '',
				content: '正在支付中',
				formContent: '',
				from: 'order',
				wxpaycode: '',
				paystatusTimer: null,
				trade_password: '',
				money: 0,
				qrcode_title: '',
				qrcode_image_show: false,
			};
		},

		onLoad(option) {

			this.pay_id = option.pay_id 
			//直接支付
			if (option.ordersn) {
				this.ordersn = option.ordersn

				this.defaultpay = option.pay_type

				if (option.redirect_url) {
					this.redirect_url = decodeURIComponent(option.redirect_url)

					uni.setStorage({
						key: 'topay_redirect_url',
						data: JSON.stringify({
							link: encodeURIComponent(this.redirect_url),
						})
					});
				} else {
					//从缓存中获取
					uni.getStorage({
						key: 'topay_redirect_url',
						success: (res) => {
							let data = JSON.parse(res.data)
							this.redirect_url = decodeURIComponent(data.link);
						},
						fail: (e) => {

						}
					});
				}



				this.link = this.redirect_url
				if (option.code) {
					this.wxpaycode = option.code
				}

				if (option.redirect) {
					this.redirect = option.redirect
				}







				this.pay();

			} else {
				this.order_id = option.id;

				if (option.from) {
					this.from = option.from

					// #ifdef H5

					let url = option.link;


					for (let key in option) {
						if (key == 'link' || key == 'id' || key == 'from') {

						} else {
							if (option[key] != '') url += '&';
							url += key + '=' + encodeURIComponent(option[key])
						}
					}
					this.link = url;
					if (!this.isWeixin) {
						window.location.href = this.link
					}
					// #endif


				}
			}










		},
		onShow() {

		},
		methods: {
			//发起支付
			pay() {

				this.qrcode_image_show = false



				var that = this
				switch (this.defaultpay) {
					case 'defaultpay': //余额支付
						if (!this.noneed_userinput_pass && !this.trade_password) {
							this.$util.msg('请输入交易密码');
							return;
						}
						break;
					case 'alipay': //支付宝支付
						this.qrcode_title = '支付宝支付'
						break;
					case 'wxpay': //微信支付
					case 'wechat': //微信支付
						this.qrcode_title = '微信支付'


						break;
					case 'qqpay': //QQ支付

						this.qrcode_title = 'QQ支付'

						break;
				}


				let wxpaycode = this.wxpaycode
				this.wxpaycode = ''

				this.$u.api.pay({
					pay_id:this.pay_id,
					ordersn: this.ordersn,
					gateway: this.defaultpay,
					trade_password: this.trade_password,
					money: this.money,
					wxpaycode: wxpaycode,
					redirect: this.redirect,

				}).then((res) => {
					if (this.paystatusTimer) {
						clearInterval(this.paystatusTimer)
					}


					if (this.defaultpay != 'defaultpay') {
						this.ordersn = res.order_sn
						this.paystatusTimer = setInterval(() => {
							this.paystatus()
						}, 2000)
					} else {
						// 余额支付直接跳到订单详情
						this.ordersn = ''
						this.order_id = ''

						this.$util.msg('支付成功');
						setTimeout(() => {
							this.$util.on(this.redirect_url);
						}, 1000)

						return;
					}

					//1 二维码支付 2 跳转网址 3 打开应用 4 微信公众号支付 5 微信小程序支付 6 微信app支付 7 支付宝app支付
					switch (res.url_type) {
						case 1:

							this.qrcode_url = res.url
							// window.location.href = res.url
							this.qrcodeshow = true
							//生成二维码
							//#ifdef H5

							
							// if(this.$util.browserType('weixin')){

							// 	window.location.href = res.url
							// 	// this.$util.msg(res.url)

							// }
							//#endif

							break;
						case 2:

							//#ifdef MP-WEIXIN


							//#endif

							//#ifdef H5

							//微信浏览器
							// if (this.$util.browserType('weixin')) {
							// uni.setStorage({
							// 	key: 'topay_link',
							// 	data: JSON.stringify({
							// 		link:  encodeURIComponent(res.url),
							// 	})
							// });

							// 	this.$util.on('/pages/common/topay?id=' + this.order_id + '&link=' +
							// 		encodeURIComponent(res.url) + '&from=' + this.defaultpay)
							// } else {
							window.location.href = res.url
							// }


							//#endif
							//#ifdef APP
							this.$util.on(res.url);

							//#endif

							break;
						case 3:


							//#ifdef H5
							window.location.href = res.url
							//#endif

							break;

						case 4: //微信公众号支付
							//#ifdef H5
							jWeixin.config({
								debug: false, // 开启调试模式,调用的所有api的返回值会在客户端alert出来，若要查看传入的参数，可以在pc端打开，参数信息会通过log打出，仅在pc端时才会打印。
								appId: res.pay_data.appId, // 必填，公众号的唯一标识
								timestamp: res.pay_data.timeStamp, // 必填，生成签名的时间戳
								nonceStr: res.pay_data.nonceStr, // 必填，生成签名的随机串
								signature: res.pay_data.paySign, // 必填，签名
								jsApiList: [ //这里是需要用到的接口名称  
									// 'checkJsApi', //判断当前客户端版本是否支持指定JS接口  
									// 'onMenuShareAppMessage', //分享接口  
									// 'getLocation', //获取位置  
									// 'openLocation', //打开位置  
									// 'scanQRCode', //扫一扫接口  
									'chooseWXPay', //微信支付  
									// 'chooseImage', //拍照或从手机相册中选图接口  
									// 'previewImage', //预览图片接口  
									// 'uploadImage' //上传图片  
								], // 必填，需要使用的JS接口列表
								openId: this.userinfo.wxgzh_openid
							});
							//付款
							jWeixin.chooseWXPay({
								appId: res.pay_data.appId,
								timestamp: res.pay_data
									.timeStamp, // 支付签名时间戳，注意微信jssdk中的所有使用timestamp字段均为小写。但最新版的支付后台生成签名使用的timeStamp字段名需大写其中的S字符
								nonceStr: res.pay_data.nonceStr, // 支付签名随机串，不长于 32
								package: res.pay_data
									.package, // 统一支付接口返回的prepay_id参数值，提交格式如：prepay_id=\*\*\*）
								signType: res.pay_data.signType, // 签名方式，默认为'SHA1'，使用新版支付需传入'MD5'
								paySign: res.pay_data.paySign, // 支付签名
								success: function(res) {


									// 余额支付直接跳到订单详情
									that.ordersn = ''
									that.order_id = ''
									if (that.paystatusTimer) {
										clearInterval(that.paystatusTimer)
									}
									that.$util.msg('支付成功');
									setTimeout(() => {
										that.$util.on(that.redirect_url);
									}, 1000)


								},
								cancel: function(res) {
									that.$util.msg('取消支付');
									if (that.paystatusTimer) {
										clearInterval(that.paystatusTimer)
									}
									setTimeout(() => {
										that.$util.on(that.redirect_url);
									}, 1000)
								},
								fail: function(res) {
									that.$util.msg('付款失败');
									if (that.paystatusTimer) {
										clearInterval(that.paystatusTimer)
									}
									setTimeout(() => {
										that.$util.on(that.redirect_url);
									}, 1000)

								}
							});

							//#endif
							break;
						case 5: //微信小程序支付

							// #ifdef MP
							let pay_data = res.pay_data
							let mp_pay_name = ''
							if (uni.requestOrderPayment) {
								mp_pay_name = 'requestOrderPayment'
							} else {
								mp_pay_name = 'requestPayment'
							}

							uni.showLoading({
								title: `支付中`
							});

							uni[mp_pay_name]({
								timeStamp: pay_data.timeStamp,
								nonceStr: pay_data.nonceStr,
								package: pay_data.package,
								signType: pay_data.signType,
								paySign: pay_data.paySign,
								success: function(res) {
									uni.hideLoading();

									that.$util.msg(res.msg);

								},
								fail: function(e) {
									uni.hideLoading();
									that.$util.msg('取消支付')
								},
								complete: function(e) {
									uni.hideLoading();
									if (e.errMsg == 'requestPayment:cancel' || e.errMsg ==
										'requestOrderPayment:cancel') return
									that.$util.msg('取消支付');
								},
							});
							// #endif




							break;
						case 6: //微信app支付


							// #ifdef APP-PLUS
							console.log(res)
							uni.showLoading({
								mask: true,
								title: '支付中...'
							});
							uni.requestPayment({
								provider: 'wxpay',
								orderInfo: res.pay_data,
								success: (e) => {
									that.$util.msg(`支付成功`)


								},
								fail: (e) => {
									that.$util.msg(`支付失败`)

								},
								complete: () => {
									// 余额支付直接跳到订单详情
									that.ordersn = ''
									that.order_id = ''
									if (that.paystatusTimer) {
										clearInterval(that.paystatusTimer)
									}

									uni.hideLoading()
								},
							});
							// #endif

							break;
						case 7: //支付宝app支付
							// #ifdef APP-PLUS

							uni.showLoading({
								mask: true,
								title: '支付中...'
							});
							uni.requestPayment({
								provider: 'alipay',
								orderInfo: res.pay_data,
								success: (e) => {
									that.$util.msg(`支付成功`)


								},
								fail: (e) => {
									console.log(e)
									that.$util.msg(`支付失败`)

								},
								complete: (e) => {
									console.log(e)
									// 余额支付直接跳到订单详情
									that.ordersn = ''
									that.order_id = ''
									if (that.paystatusTimer) {
										clearInterval(that.paystatusTimer)
									}

									uni.hideLoading()
								},
							});
							// #endif

							break;

					}

				})
			},

			paystatus() {

				this.$u.api.payStatus({
					ordersn: this.ordersn,
					ordertype: 2,
				}).then((res) => {

					if (res.status == 1) {
						let order_id = this.order_id
						this.ordersn = ''
						this.order_id = ''

						this.$util.msg('充值成功');

						clearInterval(this.paystatusTimer)

						this.$u.vuex('userinfo.balance', this.$util.bcadd(this.userinfo.balance, this.money));
						setTimeout(() => {
							this.$util.on(this.redirect_url);
						}, 1000)

					}
				}).catch((e) => {
					clearInterval(this.paystatusTimer)
				})
			},


			//排序
			alphabeticSorting(params) {
				return params.sort((a, b) => {
					let x = a.key,
						y = b.key;
					return x > y ? 1 : x < y ? -1 : 0;
				});
			},
			copyLink() {
				uni.setClipboardData({
					data: this.link,
					success() {
						uni.showToast({
							title: '复制成功',
							icon: 'success'
						});
					},
					fail() {
						uni.showToast({
							title: '复制失败',
							icon: 'none'
						});
					}
				});
			},

			goDetail() {
				uni.navigateTo({
					url: this.from == 'order' ? '/pages/buyer/order?id=' + this.order_id :
						'/pages/buyer/order?id=' +
						this.order_id
				});
			}
		}
	};
</script>

<style scoped>
	page {
		background-color: #ffffff;
	}
</style>

<style lang="scss" scoped scoped>
	.alipaysubmit {
		display: none;
	}

	.text-section {
		padding-top: 148rpx;
		margin-top: 185rpx;
		font-weight: bold;
		font-size: 32rpx;
		text-align: center;
		color: #111111;

		.link {
			margin-top: 16rpx;
			margin-right: 98rpx;
			margin-left: 98rpx;
			white-space: pre-wrap;
			overflow-wrap: break-word;
			font-weight: normal;
			color: #666666;
		}
	}

	.button-section {
		margin-top: 95rpx;
		margin-right: 98rpx;
		margin-left: 98rpx;

		.button {
			height: 80rpx;
			border-radius: 40rpx;
			font-size: 30rpx;
			line-height: 80rpx;

			~.button {
				margin-top: 32rpx !important;
			}

			&.copy {
				background-color: #333333;
				color: #ffffff;
			}

			&.off {
				border: 2rpx solid #999999;
				color: #666666;
			}
		}
	}

	.hint {
		position: fixed;
		top: 0;
		right: 0;
		bottom: 0;
		left: 0;
		padding-top: 156rpx;
		padding-left: 144rpx;
		background: url("data:image/png;base64,") calc(100% - 32rpx) 12rpx/229rpx 178rpx no-repeat;
		font-weight: 500;
		font-size: 30rpx;
		line-height: 68rpx;
		color: #c1c1c1;
		background-color: rgba(0, 0, 0, 0.8);

		.iconfont {
			margin-left: 10rpx;
			font-weight: bold;
			font-size: 30rpx;
		}
	}
</style>